{
  "domain_analysis": {
    "business_context": "A courier-tracking feature is proposed to show customers their courier's real-time location during delivery. Two internal stakeholder teams have issued directly contradictory requirements: Customer Success demands full GPS transparency as a competitive differentiator, while Operations demands no location sharing due to driver retention concerns. This is a business-level conflict that cannot be resolved by engineering — it requires executive arbitration.",
    "bounded_context": "Delivery Tracking / Last-Mile Visibility",
    "ubiquitous_language": [
      { "term": "Courier", "definition": "The driver or delivery person physically transporting a package to the customer." },
      { "term": "Real-time location", "definition": "The courier's GPS coordinates updated at frequent intervals during an active delivery." },
      { "term": "Active delivery", "definition": "The period from when a courier picks up a package to when it is delivered or the delivery attempt concludes." },
      { "term": "Location sharing", "definition": "The act of making courier GPS data visible to the end customer." },
      { "term": "Driver retention", "definition": "The ability to keep couriers working on the platform; a direct operational cost and capacity concern." },
      { "term": "Customer transparency", "definition": "Providing customers with visibility into the delivery process, cited as a competitive differentiator." }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "Courier is stationary for extended period (e.g., traffic, break) and customer sees no movement", "expected_behavior": "Undefined — full GPS would expose this, raising customer anxiety and driver surveillance concerns simultaneously." },
    { "scenario": "Courier deviates from expected route for personal reasons", "expected_behavior": "Undefined — exact GPS exposes private behavior; no GPS leaves customer uninformed about delay." },
    { "scenario": "Courier is completing multiple deliveries on same route", "expected_behavior": "Undefined — customer sees courier near them but not arriving, causing frustration. Operations views this as a batching optimization detail customers should not see." },
    { "scenario": "Courier ends shift or reassignment mid-delivery", "expected_behavior": "Undefined — location disappears or jumps, confusing customer if tracking is live." },
    { "scenario": "Courier location data used for performance monitoring or discipline", "expected_behavior": "Undefined — if GPS data exists, Operations or management may repurpose it, deepening the surveillance concern regardless of customer visibility." }
  ],

  "business_impact": {
    "financial": "Both sides carry significant financial risk. Losing drivers increases recruitment and training costs (typically $3K-$5K per driver in logistics). Losing customers due to poor tracking experience reduces revenue. The wrong decision in either direction has direct P&L impact. This requires quantified data from both teams before resolution.",
    "operational": "Driver retention directly constrains delivery capacity. If couriers leave the platform due to surveillance concerns, delivery SLAs degrade, costs rise (surge hiring, contractor premiums), and service quality drops. Conversely, lack of tracking increases customer support call volume ('where is my package?') which is a measurable ops cost.",
    "user": "Two distinct user groups with opposing needs. Customers want certainty and control during the delivery window. Couriers want autonomy and dignity while working. Both are 'users' of the system. Privileging one group's experience destroys the other's.",
    "risk": "HIGH. Shipping either requirement as stated will cause measurable harm to the business. Full GPS tracking risks driver attrition and potential labor/privacy regulatory exposure (GDPR, state privacy laws). No tracking risks customer churn and competitive disadvantage. There is also reputational risk if driver surveillance practices become public.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Directly affected — their delivery experience and sense of control depends on the resolution." },
      { "group": "Couriers/Drivers", "impact": "Directly affected — their working conditions, sense of autonomy, and retention decision depends on what location data is exposed." },
      { "group": "Customer Success team", "impact": "Their KPIs (CSAT, NPS, churn) are tied to transparency features they are advocating for." },
      { "group": "Operations team", "impact": "Their KPIs (driver retention, capacity, cost-per-delivery) are tied to the driver experience they are protecting." },
      { "group": "Legal/Compliance", "impact": "NOT YET CONSULTED — real-time employee location sharing to third parties has regulatory implications (GDPR Article 6/9, CCPA, state biometric/location laws, labor law)." },
      { "group": "Executive leadership", "impact": "Must arbitrate this conflict — it is a strategic business decision about which side of the marketplace to prioritize, not a feature decision." }
    ]
  },

  "confidence": {
    "level": 15,
    "reasoning": "Confidence is critically low because the two authoritative stakeholder teams have issued mutually exclusive requirements, both marked as non-negotiable. There is no spec — there is a contradiction. No acceptance criteria can be defined until this is resolved at the executive level. Additionally, Legal/Compliance has not been consulted on what may be a regulated activity.",
    "high_confidence_areas": [
      "The two requirements are genuinely contradictory and cannot both be satisfied as stated",
      "This is a business strategy decision, not a technical design decision",
      "Legal/regulatory review is required before any implementation"
    ],
    "low_confidence_areas": [
      "Which stakeholder group's needs should take priority",
      "Whether a compromise position (e.g., zone-based tracking, ETA-only, anonymized proximity) would satisfy either team",
      "The actual quantified impact of driver attrition vs customer churn",
      "Regulatory exposure in the jurisdictions where the company operates"
    ],
    "assumptions": [
      "Both teams have legitimate, evidence-based concerns (not assumed — needs verification with data)",
      "There is no existing executive decision or company policy that already resolves this conflict",
      "The company operates in jurisdictions where employee location privacy may be regulated"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "Customer Success requires showing exact courier GPS coordinates to customers at all times during delivery. Operations requires never showing courier location to customers. These are mutually exclusive requirements from two teams with equal organizational authority over this domain. Engineering cannot resolve this — it is a strategic business decision about marketplace priorities (demand-side vs supply-side).",
      "affected_stakeholders": ["Customers", "Couriers/Drivers", "Customer Success", "Operations", "Legal/Compliance", "Executive Leadership"],
      "options": [
        "A: Full GPS transparency (Customer Success wins) — risk driver attrition and regulatory exposure",
        "B: No location sharing (Operations wins) — risk customer churn and competitive disadvantage",
        "C: Compromise — zone-based or ETA-based tracking that provides customer confidence without exposing exact courier location (e.g., 'Your courier is 3 minutes away' with a neighborhood-level radius, not a GPS pin)",
        "D: Opt-in model — couriers consent to location sharing with incentive (e.g., higher pay tier for 'tracked' deliveries), customers get tracking only when a consenting courier is assigned"
      ],
      "recommendation": "Option C (zone-based/ETA tracking) is the most common industry resolution and likely satisfies the core need of both teams: customers get delivery confidence without exact surveillance, drivers retain autonomy. However, this MUST be decided by executive leadership after reviewing quantified driver attrition data, customer satisfaction data, and a legal opinion on location sharing in operating jurisdictions. Do NOT build anything until this is resolved."
    },
    {
      "type": "missing_context",
      "description": "Legal/Compliance has not been consulted. Sharing real-time employee GPS coordinates with third parties (customers) may violate GDPR (if operating in EU), state privacy laws (California, Illinois, etc.), or labor regulations. This is not optional — it is a potential liability blocker that could override both teams' preferences.",
      "affected_stakeholders": ["Legal/Compliance", "Executive Leadership", "Couriers/Drivers"],
      "options": [
        "Obtain legal opinion before any design work proceeds",
        "Proceed with technical design but gate launch on legal review"
      ],
      "recommendation": "Obtain legal opinion before any design work. If location sharing is legally constrained, it narrows the solution space and may resolve the stakeholder conflict by eliminating Option A entirely."
    }
  ],

  "rejection_reasons": [
    { "violation": "Cannot define acceptance criteria for contradictory requirements", "business_rule_broken": "Customer Success and Operations have issued mutually exclusive directives. Implementing either one as stated violates the other team's stated non-negotiable constraint." },
    { "violation": "No legal review of employee location sharing", "business_rule_broken": "Sharing real-time worker GPS data with customers is a potentially regulated activity. No implementation should proceed without legal clearance." }
  ]
}

